INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Reporting and search$q$, $q$Elasticsearch-backed search and reporting dashboards accessible via Grafana on higher tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$REST API and integrations$q$, $q$Connects with Slack, GitHub, GitLab, and other tools through a documented REST API.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Role-based access and custom objects$q$, $q$Configure custom ticket objects and granular roles for larger support teams.$q$, 7);
