INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Interface is functional but less polished than premium SaaS helpdesks$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Channels like WhatsApp and Facebook are reserved for the top hosted tier$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Is Zammad free?$q$, $q$Yes, the self-hosted, open-source edition of Zammad is free to download and run on your own servers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$What is the difference between self-hosted and hosted Zammad?$q$, $q$Self-hosted Zammad runs on your own infrastructure at no license cost, while hosted Zammad is a paid subscription run on Zammad's German-based servers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Where is Zammad's hosted data stored?$q$, $q$Zammad's hosted cloud plans store data exclusively in German data centers, which are ISO27001-certified.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$How much do AI features cost?$q$, $q$Optional AI features are billed separately at roughly EUR 0.03 per AI call, in addition to the base subscription.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Can I migrate from another helpdesk tool?$q$, $q$Yes, Zammad supports migration from other ticketing systems, including OTRS, and its open API supports custom data imports.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$What channels does Zammad support?$q$, $q$Email, web forms, SMS, chat, Telegram, Facebook, and WhatsApp, depending on the plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Does Zammad offer phone support as a channel?$q$, $q$Yes, phone support is available starting with the Plus v2 hosted plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Is there a limit on the number of agents?$q$, $q$Hosted plans cap agents at 5 on Starter v2 and 35 on Professional v2, while Plus v2 and the self-hosted edition support unlimited agents.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$GDPR-compliant helpdesk$q$, $q$Run a support desk with data residency requirements met via German-hosted infrastructure.$q$, $q$EU-based SMBs and IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$OTRS migration$q$, $q$Replace legacy ticketing systems like OTRS with a modern, actively developed open-source alternative.$q$, $q$IT support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Affordable multichannel support$q$, $q$Consolidate email, chat, and social support channels without high per-agent SaaS pricing.$q$, $q$Growing customer support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full core ticketing platform","Self-managed deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Starter v2 (Hosted)$q$, $q$EUR 7/agent/month (annual) or EUR 9/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 5 agents","Email, web form, and SMS channels","Triggers, macros, and schedulers"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Professional v2 (Hosted)$q$, $q$EUR 16/agent/month (annual) or EUR 18/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 35 agents","SLAs","Monolingual knowledge base","Optional AI features","Chat and Telegram channels"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Plus v2 (Hosted)$q$, $q$EUR 25/agent/month (annual) or EUR 27/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited agents","Phone support","Facebook and WhatsApp channels","Multilingual knowledge base","Standard reporting"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$Self-Hosted Support (Business/Enterprise/Corporation)$q$, $q$From EUR 2,999/year$q$, $q$annual$q$, NULL, $q$["Tiered support response times","Set number of service requests","Security advisories and patch guidance"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$overview$q$, $q$What Is Zammad$q$, 2, ARRAY[$q$Zammad is an open-source, web-based helpdesk and customer support ticketing system founded in Berlin in 2016 by Martin Edenhofer, previously a contributor to the OTRS ticketing project. Its name is Bavarian for together, reflecting its focus on collaborative support workflows across support agents, customers, and the open-source community.$q$, $q$The platform is available both as a free, self-hosted open-source edition and as a hosted cloud service run by Zammad GmbH from German data centers, giving organizations a choice between full infrastructure control and a managed, GDPR-friendly hosted option.$q$, $q$Zammad centers on unifying support requests from multiple channels, including email, web forms, SMS, chat, and social platforms, into a single ticketing interface with automation, SLAs, and reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zammad handles ticketing across email, web forms, SMS, and, on higher tiers, chat, Telegram, Facebook, and WhatsApp, giving support teams one interface for multichannel conversations. Triggers, macros, and schedulers automate routine ticket handling and routing.$q$, $q$Higher hosted tiers add SLA management, custom ticket objects, role-based permissions, and both monolingual and multilingual knowledge bases, along with Elasticsearch-powered search and reporting accessible via Grafana.$q$, $q$Optional AI features, including automatic language detection and AI-assisted reply suggestions, are available for an additional per-call fee, while a REST API and native integrations with Slack, GitHub, and GitLab support deeper workflow automation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted, open-source edition of Zammad is free to download and run on your own servers, with no license fee, though organizations are responsible for their own hosting, backups, and updates.$q$, $q$Hosted cloud plans start with Starter v2 at roughly EUR 7 per agent per month (annual billing) for up to five agents, scaling to Professional v2 at roughly EUR 16 to 18 per agent per month for up to 35 agents, and Plus v2 at roughly EUR 25 to 27 per agent per month for unlimited agents, each unlocking more channels and features.$q$, $q$Organizations that self-host but want vendor support can buy annual support contracts, Business, Enterprise, or Corporation, priced from about EUR 2,999 to EUR 9,999 per year, which include a set number of service requests and tiered response-time guarantees; optional AI features are billed separately per call.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8ad76ec7-95d0-4c9d-8183-877e0a53b6e2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Rooftop-accurate tax calculations$q$, $q$Geospatial rate determination for precise sales tax calculation down to the address level.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Real-time address validation$q$, $q$Validates customer addresses in real time to ensure accurate tax jurisdiction assignment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Proactive nexus monitoring$q$, $q$Tracks economic nexus thresholds across states with early-warning alerts before obligations are triggered.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Automated registrations$q$, $q$Handles state and Canadian tax registrations and account setup on the business's behalf.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$AI-assisted filing$q$, $q$Uses AI to help prepare and file sales tax returns across jurisdictions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Direct ACH remittance$q$, $q$Remits collected sales tax directly to state authorities via ACH.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Notice management$q$, $q$Daily monitoring of state tax portals to catch and resolve compliance notices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Cross-border Canadian coverage$q$, $q$GST, HST, PST, and QST calculations plus Canadian registration and filing support.$q$, 7);
