INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$What does Zamp actually do?$q$, $q$Zamp is a fully managed sales tax compliance service that handles nexus monitoring, calculations, registrations, filing, and remittance for e-commerce and SaaS businesses across the US and Canada.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Is Zamp free to try?$q$, $q$Zamp offers a Free plan that includes a one-time nexus analysis, liability exposure estimate, and a consultation with a tax expert.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Does Zamp handle Canadian sales tax?$q$, $q$Yes, Zamp's U.S. plus Canada plan covers GST, HST, PST, and QST calculations along with Canadian registrations and filing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$How is Zamp different from TaxJar or Avalara?$q$, $q$Zamp emphasizes a fully managed service backed by former state tax auditors, rather than a purely self-serve software product.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Does Zamp file and remit taxes on my behalf?$q$, $q$Yes, Zamp handles return preparation, filing, and direct ACH remittance to state tax authorities.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Who prepares my sales tax returns?$q$, $q$Zamp uses AI-assisted preparation combined with oversight from its team of dedicated tax experts, including former state auditors.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Does Zamp integrate with my ecommerce platform?$q$, $q$Zamp offers integrations for common ecommerce platforms, including a BigCommerce app, to pull sales data for tax calculation.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$How is Zamp priced?$q$, $q$Beyond the free nexus analysis, Zamp's U.S. and U.S. plus Canada plans are custom-quoted based on a business's specific compliance footprint.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Multi-state ecommerce compliance$q$, $q$Automate sales tax nexus tracking, calculation, and filing across many US states.$q$, $q$Ecommerce businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Managed compliance for finance teams$q$, $q$Offload sales tax operations to a managed service instead of building an in-house tax function.$q$, $q$Finance and accounting teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$US and Canada expansion$q$, $q$Manage cross-border sales tax obligations when expanding from the US into Canada.$q$, $q$SaaS and ecommerce companies expanding internationally$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$Free$q$, $q$$0$q$, $q$one-time$q$, NULL, $q$["One-time nexus analysis","Historical liability exposure estimate","Product taxability review","30-minute expert consultation","Rate-limited API sandbox access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$U.S. Plan$q$, $q$Custom quote$q$, $q$custom$q$, NULL, $q$["Rooftop-accurate calculations","Automated registrations","AI-assisted filing","Direct ACH remittance","Notice management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$U.S. + Canada Plan$q$, $q$Custom quote$q$, $q$custom$q$, NULL, $q$["All U.S. Plan features","GST/HST/PST/QST calculations","Canadian threshold monitoring","Canadian registrations and filing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$overview$q$, $q$What Is Zamp$q$, 2, ARRAY[$q$Zamp is a fully managed sales tax compliance company founded in 2022 by CEO Rohit Bhadange and Edward Lando, headquartered in San Francisco, California. Rather than offering only self-serve software, Zamp pairs its platform with a team that includes former state tax auditors to handle sales tax compliance end to end for e-commerce and SaaS businesses.$q$, $q$Zamp is backed by investors including the CEOs of ThredUp, Lands End, Kayak, Italic, and Drizly, and has raised over fourteen million dollars according to founder interviews.$q$, $q$The platform covers the full compliance lifecycle across the US and, more recently, Canada, from nexus monitoring through calculation, registration, filing, and remittance.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zamp calculates sales tax with rooftop-accurate, geospatial rate determination and real-time address validation, and proactively monitors nexus thresholds across states so businesses know before they trigger a new filing obligation.$q$, $q$The platform automates state registrations and account setup, uses AI to assist with return preparation, and remits collected tax directly via ACH to state authorities, removing manual filing work from finance teams.$q$, $q$Zamp also handles notice management, with daily monitoring of state tax portals, and has expanded into Canadian sales tax coverage, including GST, HST, PST, and QST calculations, Canadian threshold monitoring, and cross-border tax expertise.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca461870-55b1-4c9b-a8d8-8006576315c0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zamp offers a Free plan for businesses that want to understand their tax exposure, including a one-time nexus analysis, a historical liability exposure estimate, a product taxability review, and a thirty-minute expert consultation.$q$, $q$Beyond the free tier, Zamp's U.S. Plan and U.S. plus Canada Plan are both custom-priced and require a sales conversation, since the company scopes pricing to each business's actual multi-state or cross-border compliance footprint rather than charging flat per-filing fees.$q$, $q$This all-inclusive, quote-based pricing model is designed to avoid the overage fees and hidden add-ons that Zamp argues are common with flat per-state or per-filing pricing used by some competitors.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Thousands of app integrations$q$, $q$Connects to over 8,000 web apps to automate actions between them without code.$q$, 0);
