INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Built-in data formatting and filtering$q$, $q$Transform and filter data as it moves between apps within a Zap.$q$, 2);
