INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Zapier Interfaces$q$, $q$Build simple forms and lightweight apps that trigger automated workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$AI-powered Zap builder and Copilot$q$, $q$Use natural language to help design and build automations faster.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Webhooks and custom API integrations$q$, $q$Connect apps that lack an official Zapier integration via webhooks.$q$, 6);
