INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$What counts as a task in Zapier's pricing?$q$, $q$A task is generally one action successfully performed by a Zap, and monthly plans are priced around a set number of tasks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Is there a free plan?$q$, $q$Yes, Zapier's Free plan includes 100 tasks per month with single-step Zaps and one user.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$What is the difference between Starter, Professional, and Team plans?$q$, $q$Starter adds multi-step Zaps and premium apps, Professional adds more tasks and advanced admin features, and Team adds shared workspaces, role-based access, and SSO for unlimited users.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Can Zapier connect apps that do not have an official integration?$q$, $q$Yes, through webhooks and custom API connections, Zapier can integrate with apps outside its official app directory.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Does Zapier offer AI features?$q$, $q$Yes, Zapier includes an AI-powered Zap builder and a Copilot assistant to help build automations from natural-language descriptions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$How does Zapier handle multi-step workflows?$q$, $q$Multi-step Zaps use a feature called Paths to add conditional branching logic beyond a single trigger and action.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Is Zapier suitable for non-technical users?$q$, $q$Yes, Zapier is designed as a no-code tool with a visual builder aimed at non-technical users.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$What happens if I exceed my monthly task limit?$q$, $q$Zaps stop running additional tasks until the plan is upgraded or the usage cycle resets, depending on account settings.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Cross-app task automation$q$, $q$Automate repetitive tasks between apps like email, CRM, and spreadsheets without engineering support.$q$, $q$Small businesses and solo operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Sales and marketing lead syncing$q$, $q$Keep leads and customer data in sync across marketing, sales, and support tools.$q$, $q$Marketing and sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Multi-step operational workflows$q$, $q$Build approval chains and notification workflows spanning several apps.$q$, $q$Operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["100 tasks/month","Single-step Zaps","15-minute update intervals","1 user"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Starter$q$, $q$$19.99/month (annual) or $29.99/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["750 tasks/month","Multi-step Zaps","Premium app access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Professional$q$, $q$$49/month (annual) or $73.50/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["2,000 tasks/month","Unlimited Zaps","Premium apps","Advanced admin features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Team$q$, $q$$69/month$q$, $q$annual$q$, NULL, $q$["2,000 tasks/month","Shared workspaces","Role-based access","SSO","Unlimited users"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["5,000+ tasks/month","Unlimited users","Advanced admin controls","Technical account management"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$overview$q$, $q$What Is Zapier$q$, 2, ARRAY[$q$Zapier is a no-code workflow automation platform founded in 2011 by Wade Foster, Bryan Helmig, and Mike Knoop, who began the company as a side project in Columbia, Missouri before joining Y Combinator. It has since grown into a fully remote company with roughly 700 employees worldwide and no traditional central headquarters, though it is legally based in Sunnyvale, California.$q$, $q$The platform's core purpose is connecting web applications so that actions in one app can automatically trigger actions in another, without requiring users to write code. Zapier commonly cites support for over 8,000 app integrations.$q$, $q$Automated workflows in Zapier are called Zaps, and the platform has expanded well beyond simple two-app automations to include multi-step logic, data storage, and AI-assisted workflow building.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A Zap pairs a trigger in one app with one or more resulting actions in other apps, and Zapier supports multi-step Zaps with conditional branching through a feature called Paths, along with built-in data formatting, filtering, and delay steps.$q$, $q$Zapier Tables lets users store and manage structured data directly within the platform, while Zapier Interfaces allows building simple forms or lightweight apps that feed into automated workflows, reducing the need for separate front-end tools.$q$, $q$The platform has added AI capabilities, including an AI-powered Zap builder and a Copilot assistant that helps users describe and construct automations in natural language, alongside webhook support for connecting custom or unlisted APIs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zapier's pricing is based on monthly task volume rather than a flat seat price. The Free plan includes 100 tasks per month, limited to single-trigger, single-action Zaps with 15-minute update intervals and one user.$q$, $q$The Starter plan costs $19.99 per month billed annually and includes 750 tasks with multi-step Zaps and premium app access; the Professional plan costs $49 per month billed annually with 2,000 tasks, unlimited Zaps, and advanced admin features.$q$, $q$The Team plan costs $69 per month billed annually for 2,000 tasks with shared workspaces, role-based access, and SSO for unlimited users, while the Enterprise plan offers custom pricing for organizations needing 5,000 or more tasks and advanced governance controls.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('925daab1-05f1-463d-acca-f58f8cdc0978', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
