INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$What is Zeabur?$q$, $q$Zeabur is a cloud application deployment platform (PaaS) that lets developers deploy apps and databases with one-click, git-based workflows.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Is there a free plan?$q$, $q$Yes, Zeabur offers a Free plan with one manageable server and community support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Which cloud providers does Zeabur support?$q$, $q$Zeabur supports deployment on AWS, Google Cloud, and its own infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Does Zeabur support databases?$q$, $q$Yes, Zeabur offers built-in databases and a template marketplace for common services.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$How does billing work on Zeabur?$q$, $q$Zeabur uses a subscription-plus-usage model, with monthly plan fees plus usage-based costs depending on resource consumption.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Can I deploy from a private GitHub repository?$q$, $q$Yes, Zeabur connects directly to GitHub repositories, including private ones, for automated deployment.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Does Zeabur offer team collaboration features?$q$, $q$Yes, the Team plan includes multiple seats, role and permission management, and priority support.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$What happens if I exceed my plan's resource limits?$q$, $q$Usage beyond plan limits is billed under Zeabur's pay-as-you-go model or requires upgrading to a higher tier.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Indie project deployment$q$, $q$Deploy side projects and small apps quickly without managing servers.$q$, $q$Indie developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Startup application hosting$q$, $q$Get Heroku-like simplicity for hosting production applications without a dedicated DevOps team.$q$, $q$Early-stage startups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Multi-service deployments$q$, $q$Deploy a web app, database, and background worker together from one dashboard.$q$, $q$Small engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["1 manageable server","2 vCPU/4GB build spec","48-hour log retention","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Dev$q$, $q$$5/month$q$, $q$monthly$q$, NULL, $q$["3 manageable servers","7-day log retention","Domain purchase","Zeabur Agent"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Pro$q$, $q$$19/month$q$, $q$monthly$q$, NULL, $q$["10 manageable servers","4 vCPU/8GB build spec","30-day log retention","Advanced log search"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Team$q$, $q$$79/month (3 seats included, +$24/seat)$q$, $q$monthly$q$, NULL, $q$["Unlimited manageable servers","90-day log retention","Team roles and permissions","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Custom usage limits","Dedicated technical resources","Custom contracts"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$overview$q$, $q$What Is Zeabur$q$, 2, ARRAY[$q$Zeabur is a cloud application deployment platform, or Platform-as-a-Service (PaaS), founded in 2022 by Yuanlin Lin and headquartered in Singapore. It is built around one-click, git-based deployment that lets developers push code from GitHub and have it automatically built and deployed to the cloud.$q$, $q$The platform supports multiple underlying cloud providers, including AWS and Google Cloud, in addition to Zeabur's own infrastructure, and includes a marketplace of pre-built templates for common services and databases.$q$, $q$Zeabur positions itself as an AI-assisted DevOps platform, aiming to reduce the manual configuration typically required to deploy and manage cloud applications.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zeabur automatically detects a project's framework or language and builds it without requiring a manually written Dockerfile in most cases, and supports one-click deployment directly from a connected GitHub repository.$q$, $q$The platform provides built-in databases and a template marketplace, automatic custom domains with HTTPS, and log retention and search features that scale with each pricing tier.$q$, $q$Team-oriented features, including role and permission management, multiple manageable servers, and priority support, are available on higher plans, alongside AI-assisted DevOps tooling aimed at simplifying ongoing operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4c2db9c-c418-40cf-8387-d72c25bbc544', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zeabur's Free plan costs nothing and includes one manageable server, a 2 vCPU/4GB build specification, 48-hour log retention, and community support.$q$, $q$Paid plans start with Dev at $5 per month (three manageable servers, 7-day log retention) and Pro at $19 per month (ten manageable servers, 4 vCPU/8GB build spec, 30-day log retention, advanced log search).$q$, $q$The Team plan costs $79 per month for three seats, with additional seats at $24 each, and includes unlimited manageable servers and 90-day log retention, while Enterprise pricing is custom for organizations needing dedicated resources and contracts.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Centralized voice-of-customer capture$q$, $q$Collects feedback via in-app widgets, customer portals, call transcripts, and CSV import.$q$, 0);
