INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Public and private roadmap sharing$q$, $q$Share roadmaps internally or publish customer-facing roadmaps.$q$, 4);
