INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$AI-generated release notes$q$, $q$Automatically draft and distribute release notes with custom branding.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$5,000+ workflow integrations$q$, $q$Connects to a large library of integrations to centralize feedback sources.$q$, 7);
