INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$What is Zeda.io used for?$q$, $q$Zeda.io is used to collect customer feedback, generate AI-driven product insights, build revenue-linked roadmaps, and publish AI-generated release notes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Does Zeda.io offer a free trial?$q$, $q$Yes, Zeda.io offers a 14-day free trial of its Standard plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Does Zeda.io integrate with Jira and Linear?$q$, $q$Yes, Zeda.io offers two-way synchronization with both Jira and Linear.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$How does Zeda.io use AI?$q$, $q$Zeda.io uses AI to analyze feedback for pain points, sentiment, and trends, and to auto-generate release notes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Can I share roadmaps publicly with customers?$q$, $q$Yes, Zeda.io supports both private internal roadmaps and public customer-facing roadmaps.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Who is Zeda.io built for?$q$, $q$Zeda.io is built for product managers and product teams that want to tie prioritization to customer feedback and revenue impact.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Does Zeda.io support release notes?$q$, $q$Yes, Zeda.io includes AI-generated release notes with custom branding and distribution across multiple channels.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$What is included in the Standard plan?$q$, $q$The Standard plan includes VoC and feedback management, AI product insights, revenue-first roadmaps, and AI release notes.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Centralizing customer feedback$q$, $q$Bring scattered feedback from multiple channels into one AI-analyzed system.$q$, $q$Product managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Revenue-linked roadmap planning$q$, $q$Prioritize roadmap items based on customer feedback and revenue impact.$q$, $q$Product leadership teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Automated release communication$q$, $q$Generate and distribute AI-written release notes across channels.$q$, $q$Product marketing and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$Standard$q$, $q$From $499/month$q$, $q$annual$q$, NULL, $q$["VoC and feedback management","AI product insights","Revenue-first roadmaps","AI release notes","Jira and Linear two-way sync"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$overview$q$, $q$What Is Zeda.io$q$, 2, ARRAY[$q$Zeda.io is an AI-powered product discovery and management platform founded in 2021, headquartered in California with an additional team in India, and employing roughly 25 people. It raised a pre-seed round of about $550,000 in 2021 and a further $1.2 million after launching publicly and landing its first paid customer in 2022.$q$, $q$The platform is built around voice-of-customer, or VoC, led product management, unifying feedback collection, AI-driven insight generation, roadmapping, and release notes into a single suite rather than requiring separate point tools.$q$, $q$Zeda.io is designed for product teams that want to tie prioritization and roadmap decisions directly back to customer feedback and revenue impact.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zeda.io captures customer feedback through in-app widgets, public and private customer portals, imported call transcripts, and CSV uploads, and connects to more than 5,000 workflows to centralize signals from many sources.$q$, $q$Its AI layer analyzes collected feedback to surface product area and pain-point trends, sentiment analysis, and revenue impact estimates, with pre-made insight templates and automated alerts.$q$, $q$The roadmapping module supports OKR and impact mapping, custom prioritization fields, and public or private roadmap sharing, with two-way sync to Jira and Linear, while an AI release notes feature automatically drafts and distributes updates with custom branding and analytics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ac86fa0-12e3-4373-bceb-3db29dc3719e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zeda.io sells a single Standard plan starting at approximately $499 per month, billed annually, which includes the full suite: VoC and feedback management, AI product insights, revenue-first roadmaps, and AI-generated release notes.$q$, $q$A 14-day free trial is available for teams to evaluate the platform before committing to the annual plan.$q$, $q$Zeda.io does not offer a low-cost monthly plan, framing its annual-only billing as a long-term commitment to customer success rather than a flexible, pay-as-you-go pricing structure.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Multiple meeting types$q$, $q$One-on-one, group, collective, round-robin, and flexi meeting formats for different scheduling needs.$q$, 0);
