INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Is Zeeg free to use?$q$, $q$Yes, Zeeg's Starter plan is free and includes unlimited events and video conferencing integration.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Where is Zeeg's data hosted?$q$, $q$Zeeg is built and hosted in Germany, with data stored exclusively on German servers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$What meeting types does Zeeg support?$q$, $q$Zeeg supports one-on-one, group, collective, round-robin, and flexi meeting types.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$What is the Zeeg AI voice agent?$q$, $q$It is an AI secretary that answers inbound calls, qualifies callers, and books meetings automatically.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Does Zeeg integrate with my calendar and CRM?$q$, $q$Yes, Zeeg syncs with calendars and integrates with CRM tools starting on the Professional plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Can I accept payments through Zeeg bookings?$q$, $q$Yes, Zeeg supports online payments for paid appointments.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$What is included in the Business plan?$q$, $q$The Business plan adds round-robin scheduling, deeper CRM integrations, and routing forms on top of the Professional plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Does Zeeg offer an enterprise plan?$q$, $q$Yes, Zeeg's Enterprise plan offers custom pricing, extensive custom objects, flexible invoicing, and a dedicated account manager.$q$, 7, 'published');
