INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Business$q$, $q$EUR 16/user/month (annual) or EUR 20/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Round-robin scheduling","CRM integrations","Routing forms"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Scale$q$, $q$EUR 30/user/month (annual) or EUR 40/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Custom objects","SSO and SCIM","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Extensive custom objects","Flexible invoicing","Dedicated account manager"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$overview$q$, $q$What Is Zeeg$q$, 2, ARRAY[$q$Zeeg is a scheduling and booking platform built and hosted in Germany, with customer data stored exclusively on German servers, positioning it as a privacy-first, GDPR-compliant alternative to US-based scheduling tools such as Calendly.$q$, $q$The platform supports several distinct meeting formats, including one-on-one, group, collective, round-robin, and flexi meetings, covering everything from simple consultations to complex multi-host scheduling logic.$q$, $q$A more recent addition is Zeeg's built-in AI voice agent, which answers inbound calls, qualifies callers, and books meetings automatically, extending the platform beyond web-based booking pages.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core scheduling features include calendar sync, availability management, automated rescheduling, and reminders and confirmations delivered by both email and SMS.$q$, $q$Zeeg supports online payments for paid bookings, customizable intake forms, access controls and permissions, and reporting and statistics on booking activity across a team.$q$, $q$The AI voice agent acts as an automated secretary, holding natural conversations with inbound callers, qualifying them, and booking meetings without human intervention, while third-party integrations cover CRM tools, video conferencing, and workflow automation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3be42f56-bb10-429e-833e-4732e857fc3a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zeeg's Starter plan is free and includes unlimited events, event notifications, and video conferencing integration, giving individuals a fully usable no-cost entry point.$q$, $q$Paid plans start with Professional at EUR 10 per user per month billed annually, adding API and webhook access and CRM essentials, followed by Business at EUR 16 per user per month for round-robin scheduling and deeper CRM integrations.$q$, $q$The Scale plan costs EUR 30 per user per month for custom objects, SSO, and SCIM support, while Enterprise offers custom pricing with flexible invoicing and a dedicated account manager; all paid tiers include a 14-day free trial.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Deep protocol analysis$q$, $q$Analyzes dozens of network protocols in depth rather than relying only on signature matching.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$High-fidelity transaction logs$q$, $q$Produces compact, structured logs of network activity for analysis rather than just alerts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Zeek scripting language$q$, $q$A domain-specific language for writing custom detection and analysis logic.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$File extraction and analysis$q$, $q$Extracts files observed in network traffic for further inspection.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Plugin and package ecosystem$q$, $q$Extend Zeek's functionality through community packages managed by the Zeek Package Manager.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Cluster deployment$q$, $q$Distribute traffic analysis across multiple worker processes for high-throughput networks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$SIEM and threat-hunting integration$q$, $q$Feed structured logs into SIEMs and threat-hunting platforms for investigation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Network metadata for encrypted traffic$q$, $q$Surfaces metadata and behavioral signals even for traffic that cannot be decrypted.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Free and open source under a permissive BSD license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Extremely detailed, structured logs ideal for threat hunting and forensics$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Highly extensible via its own scripting language and package ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Backed and financially supported by Corelight, ensuring active development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Long track record and strong adoption in academic, government, and enterprise security teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Steep learning curve, especially for Zeek's custom scripting language$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Requires significant tuning and infrastructure to deploy at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Not a turnkey product; generated data still needs a SIEM or analyst workflow$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$No official vendor support without a commercial add-on like Corelight$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$What is Zeek and how is it different from an IDS like Snort or Suricata?$q$, $q$Zeek focuses on deep, structured logging of network activity for analysis, while tools like Snort and Suricata are primarily signature-based intrusion detection systems focused on alerts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Was Zeek previously called Bro?$q$, $q$Yes, the project was named Bro from its creation in the 1990s until it was renamed Zeek in late 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Is Zeek free to use?$q$, $q$Yes, Zeek is completely free and open source under a permissive BSD license.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Does Zeek generate alerts or just logs?$q$, $q$Zeek primarily generates detailed structured logs of network activity; alerting and correlation are typically handled by a downstream SIEM or custom Zeek scripts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$What is the Zeek Package Manager?$q$, $q$It is a tool for installing and managing community-built plugins and packages that extend Zeek's functionality.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Can Zeek run in a cluster for high-traffic networks?$q$, $q$Yes, Zeek supports cluster deployments that distribute analysis across multiple worker processes for high-throughput environments.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Who maintains Zeek today?$q$, $q$Zeek is a community-stewarded open-source project that receives significant financial and technical support from Corelight.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Does Zeek analyze encrypted traffic?$q$, $q$Zeek can extract useful metadata and behavioral signals from encrypted traffic even when it cannot decrypt the payload.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Security operations center monitoring$q$, $q$Generate detailed network traffic logs for continuous security monitoring and threat hunting.$q$, $q$Security operations center (SOC) teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Incident response and forensics$q$, $q$Use detailed network logs to investigate and reconstruct security incidents.$q$, $q$Incident response teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Custom detection engineering$q$, $q$Write custom Zeek scripts to detect environment-specific threats and behaviors.$q$, $q$Government, academic, and enterprise security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Zeek framework","Zeek scripting language","Community packages","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$overview$q$, $q$What Is Zeek$q$, 2, ARRAY[$q$Zeek is an open-source network security monitoring framework originally created by Vern Paxson, who began development in 1995 at Lawrence Berkeley National Laboratory under the name Bro, a reference to Big Brother from George Orwell's Nineteen Eighty-Four. Paxson's original 1998 paper on the system won the USENIX Security Symposium's Best Paper Award.$q$, $q$In late 2018, the project was renamed from Bro to Zeek, inspired by the pseudo-username zeek that Berkeley Lab developers had used to run their network sensors in the 1990s, and intended to better reflect the values of the project's growing community.$q$, $q$Zeek is not a company but a community-stewarded open-source project, distributed under a permissive BSD license, historically hosted at the nonprofit International Computer Science Institute (ICSI) and today financially supported and championed by Corelight, a commercial security company co-founded by Paxson.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Unlike signature-based intrusion detection tools, Zeek focuses on deep protocol analysis across dozens of network protocols, producing compact, structured, high-fidelity logs of network activity rather than primarily generating alerts.$q$, $q$Zeek includes its own domain-specific scripting language, letting security analysts write custom detection and analysis logic tailored to their environment, and supports an extensive plugin and package ecosystem through the Zeek Package Manager.$q$, $q$For high-throughput networks, Zeek supports cluster deployments that distribute traffic analysis across multiple worker processes, and its logs are commonly fed into SIEMs and threat-hunting platforms for investigation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zeek is completely free and open source under a permissive BSD license, with no paid edition or feature-gated tier.$q$, $q$There is no official vendor support included with the open-source project itself; organizations wanting commercial support or a more turnkey product typically look to Corelight, which builds a commercial platform on top of Zeek.$q$, $q$Because Zeek requires self-hosting and tuning, its real cost for most organizations lies in the infrastructure and security engineering expertise needed to deploy and operate it effectively, rather than in a license fee.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82d8db18-43fe-4252-9850-0cc4a603d607', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
