-- ── Zammad ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, AI-assisted helpdesk and ticketing platform that unifies email, chat, phone, and social channels into one support workflow.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source); hosted plans from EUR 7 per agent per month$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Zammad Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Zammad's open-source helpdesk platform: multichannel ticketing, automation, AI features, self-hosted vs cloud pricing, and how it stacks up.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zammad is an open-source, web-based helpdesk and customer support ticketing platform founded in Berlin in 2016 by Martin Edenhofer, who was previously involved in developing the OTRS ticketing system. The name Zammad comes from a Bavarian word meaning together, reflecting the product's collaborative, community-driven philosophy. Zammad is available in two deployment models: a fully free, self-hosted open-source edition that organizations install and manage on their own servers, and a hosted cloud edition run by Zammad GmbH on servers located in German data centers, which are ISO27001-certified and designed for GDPR-friendly data residency. The hosted plans start at Starter v2, priced around EUR 7 per agent per month on annual billing (or EUR 9 monthly) for up to five agents, and scale up through Professional v2 (around EUR 16 to 18 per agent per month, up to 35 agents) and Plus v2 (around EUR 25 to 27 per agent per month, unlimited agents). Higher tiers unlock more support channels, including chat, Telegram, Facebook, and WhatsApp, along with SLA management, knowledge base tools, multilingual support, Elasticsearch-backed reporting via Grafana, and GitHub or GitLab integration. Zammad also offers optional AI features, such as automatic language detection and AI-assisted responses, billed separately at roughly EUR 0.03 per AI call on top of the subscription. Organizations that prefer to self-host but still want vendor support can purchase annual support contracts named Business, Enterprise, and Corporation, priced from roughly EUR 2,999 to EUR 9,999 per year, which bundle a defined number of service requests, security advisories, and tiered response-time guarantees. Across all editions, Zammad's core functionality includes multichannel ticket management spanning email, web forms, SMS, chat, and social channels; automation through triggers, macros, and schedulers; a customer-facing knowledge base; role-based access with custom ticket objects; and a REST API for integrating with tools like Slack, GitHub, and GitLab. Because the self-hosted edition is free and fully open source, Zammad is popular with organizations that have specific data residency requirements, IT teams migrating away from OTRS or other legacy ticketing systems, and cost-conscious support teams that want multichannel capabilities without the per-agent pricing of larger SaaS helpdesks like Zendesk or Freshdesk. The tradeoff is that self-hosting requires ongoing server management, and the interface, while functional, is less polished than some premium competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8ad76ec7-95d0-4c9d-8183-877e0a53b6e2';

